import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getTravelSuggestions = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional travel assistant for "LeFlight". Help the user with this query: "${query}". Provide a concise, elegant, and inspiring response. Include a few tips for their destination if mentioned.`,
      config: {
        temperature: 0.7,
        topP: 0.9,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Maaf, LeFlight AI sedang beristirahat sejenak. Silakan coba beberapa saat lagi.";
  }
};

export const searchFlightsAI = async (origin: string, dest: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 3-4 realistic mock flight results from ${origin} to ${dest}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              airline: { type: Type.STRING },
              departureTime: { type: Type.STRING },
              arrivalTime: { type: Type.STRING },
              duration: { type: Type.STRING },
              price: { type: Type.NUMBER },
              stops: { type: Type.INTEGER }
            },
            required: ["id", "airline", "departureTime", "arrivalTime", "duration", "price", "stops"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Flight Search Error:", error);
    return [];
  }
};

