import React, { useEffect, useState } from 'react';
import { PlaneIcon } from '../constants';

const IntroAnimation: React.FC = () => {
  const [isVisible, setIsVisible] = useState(true);
  const [blurAmount, setBlurAmount] = useState(20);

  useEffect(() => {
    // Gradually reduce blur
    const startTime = Date.now();
    const duration = 3000;

    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);
      setBlurAmount(20 * (1 - progress));

      if (progress >= 1) {
        clearInterval(interval);
        setTimeout(() => setIsVisible(false), 500);
      }
    }, 16);

    return () => clearInterval(interval);
  }, []);

  if (!isVisible) return null;

  return (
    <div 
      className="fixed inset-0 z-[1000] flex items-center justify-center pointer-events-none transition-opacity duration-1000"
      style={{ 
        backdropFilter: `blur(${blurAmount}px)`,
        WebkitBackdropFilter: `blur(${blurAmount}px)`,
        backgroundColor: `rgba(240, 249, 255, ${Math.min(blurAmount / 20, 0.8)})`
      }}
    >
      <div className="absolute left-1/2 bottom-0 -translate-x-1/2 animate-plane-up">
        <PlaneIcon className="w-24 h-24 text-blue-500 drop-shadow-2xl" />
        <div className="mt-4 flex flex-col items-center">
          <div className="w-1 h-32 bg-gradient-to-t from-transparent via-blue-200 to-blue-400 opacity-30 rounded-full blur-sm"></div>
        </div>
      </div>
    </div>
  );
};

export default IntroAnimation;

