import React, { useEffect, useState } from 'react';
import { PlaneIcon } from '../constants';

const IntroAnimation: React.FC = () => {
  const [isVisible, setIsVisible] = useState(true);
  const [stage, setStage] = useState<'intro' | 'fade'>('intro');
  const [blurValue, setBlurValue] = useState(40);
  const [opacity, setOpacity] = useState(1);

  useEffect(() => {
    const duration = 4000; // Match plane animation duration
    const startTime = Date.now();

    const frame = () => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);

      // Blur starts high and clears out exponentially
      const currentBlur = 40 * Math.pow(1 - progress, 2);
      setBlurValue(currentBlur);

      if (progress > 0.7) {
        setOpacity(1 - (progress - 0.7) / 0.3);
      }

      if (progress < 1) {
        requestAnimationFrame(frame);
      } else {
        setIsVisible(false);
      }
    };

    const animId = requestAnimationFrame(frame);
    return () => cancelAnimationFrame(animId);
  }, []);

  if (!isVisible) return null;

  return (
    <div 
      className="fixed inset-0 z-[2000] flex items-center justify-center pointer-events-none"
      style={{ 
        backdropFilter: `blur(${blurValue}px)`,
        WebkitBackdropFilter: `blur(${blurValue}px)`,
        backgroundColor: `rgba(240, 249, 255, ${opacity * 0.9})`,
        opacity: opacity
      }}
    >
      {/* Dynamic Background Clouds */}
      <div className="absolute inset-0 overflow-hidden opacity-30">
        <div className="absolute top-1/4 left-[-10%] w-[40%] h-[20%] bg-white rounded-full blur-3xl animate-[cloudMove_20s_infinite_alternate]"></div>
