import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import LoadingScreen from './components/LoadingScreen';
import IntroAnimation from './components/IntroAnimation';
import FlightCard from './components/FlightCard';
import { DESTINATIONS, PlaneIcon } from './constants';
import { Flight, SearchParams } from './types';
import { getTravelSuggestions, searchFlightsAI } from './services/geminiService';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [searchParams, setSearchParams] = useState<SearchParams>({
    origin: 'Jakarta (CGK)',
    destination: '',
    date: new Date().toISOString().split('T')[0],
    passengers: 1,
    class: 'Economy'
  });
  const [flights, setFlights] = useState<Flight[]>([]);
  const [hasSearched, setHasSearched] = useState(false);
  const [aiMessage, setAiMessage] = useState<string>('');
  const [isTypingAI, setIsTypingAI] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchParams.destination) return;

    setIsLoading(true);
    setHasSearched(true);

    const results = await searchFlightsAI(searchParams.origin, searchParams.destination);

    const mockResults: Flight[] = results.length > 0 ? results.map((r: any) => ({
      ...r,
      from: searchParams.origin.split(' ')[0],
      to: searchParams.destination.split(' ')[0],
    })) : [
      {
        id: '1',
        airline: 'SkyHigh Airways',
        logo: '✈️',
        departureTime: '08:00',
        arrivalTime: '11:30',
        duration: '3h 30m',
        from: searchParams.origin.split(' ')[0],
        to: searchParams.destination.split(' ')[0],
        price: 120,
        stops: 0
      },
      {
        id: '2',
        airline: 'Azure Wings',
        logo: '☁️',
        departureTime: '13:45',
        arrivalTime: '18:15',
        duration: '4h 30m',
        from: searchParams.origin.split(' ')[0],
        to: searchParams.destination.split(' ')[0],
        price: 95,
        stops: 1
      }
    ];

    setTimeout(() => {
      setFlights(mockResults);
      setIsLoading(false);
      handleAIGreeting();
    }, 2000);
  };

