import React, { useEffect, useState } from 'react';
import { PlaneIcon } from '../constants';

const IntroAnimation: React.FC = () => {
  const [isVisible, setIsVisible] = useState(true);
  const [blurValue, setBlurValue] = useState(40);
  const [opacity, setOpacity] = useState(1);

  useEffect(() => {
    const duration = 4000;
    const startTime = Date.now();

    const frame = () => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);

      // Clear blur exponentially
      const currentBlur = 40 * Math.pow(1 - progress, 2);
      setBlurValue(currentBlur);

      // Fade out background slightly towards the end
      if (progress > 0.8) {
        setOpacity(1 - (progress - 0.8) / 0.2);
      }

      if (progress < 1) {
        requestAnimationFrame(frame);
      } else {
        setIsVisible(false);
      }
    };

    const animId = requestAnimationFrame(frame);
    return () => cancelAnimationFrame(animId);
  }, []);

  if (!isVisible) return null;

  return (
    <div 
      className="fixed inset-0 z-[2000] flex items-center justify-center pointer-events-none transition-all duration-700"
      style={{ 
        backdropFilter: `blur(${blurValue}px)`,
        WebkitBackdropFilter: `blur(${blurValue}px)`,
        backgroundColor: `rgba(240, 249, 255, ${opacity * 0.95})`,
        opacity: opacity
      }}
    >
      {/* Cinematic Diagonal Flight */}
      <div className="absolute left-0 bottom-0 animate-plane-diagonal">
        <div className="relative">
          <PlaneIcon className="w-40 h-40 text-blue-500 drop-shadow-[0_25px_60px_rgba(37,99,235,0.4)]" />
          {/* Subtle trail */}
          <div className="absolute -bottom-16 left-1/2 -translate-x-1/2 flex space-x-16 opacity-25">
            <div className="w-2 h-80 bg-gradient-to-t from-transparent via-blue-200 to-white rounded-full blur-lg"></div>
            <div className="w-2 h-80 bg-gradient-to-t from-transparent via-blue-200 to-white rounded-full blur-lg"></div>
          </div>
        </div>
      </div>

      {/* Slow revealing Brand center */}
      <div className="absolute text-center">
         <h2 
           className="text-8xl font-black tracking-tighter text-blue-600/10 select-none transition-opacity duration-1000"
           style={{ opacity: 1 - opacity }}
         >
           LeFlight
         </h2>
      </div>
    </div>
  );
};

export default IntroAnimation;

