export const searchFlightsAI = async (origin: string, dest: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 3-4 realistic mock flight results from ${origin} to ${dest}. Include a realistic status (On Time, Delayed, or Cancelled).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              airline: { type: Type.STRING },
              departureTime: { type: Type.STRING },
              arrivalTime: { type: Type.STRING },
              duration: { type: Type.STRING },
              price: { type: Type.NUMBER },
              stops: { type: Type.INTEGER },
              status: { type: Type.STRING, description: "Flight status: On Time, Delayed, or Cancelled" }
            },
            required: ["id", "airline", "departureTime", "arrivalTime", "duration", "price", "stops", "status"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Flight Search Error:", error);
    return [];
  }
};

