import React, { useState, useEffect, useRef, useCallback } from 'react';
import { PlaneIcon } from '../constants';

const GRAVITY = 0.6;
const JUMP_STRENGTH = -8;
const OBSTACLE_SPEED = 3.5;
const OBSTACLE_SPAWN_RATE = 1500;
const BIRD_SIZE = 34;
const CANVAS_WIDTH = 300;
const CANVAS_HEIGHT = 450;
const PIPE_WIDTH = 50;
const PIPE_GAP = 160;

interface Obstacle {
  x: number;
  gapTop: number;
  passed: boolean;
}

const FlightGame: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [birdY, setBirdY] = useState(CANVAS_HEIGHT / 2);
  const [velocity, setVelocity] = useState(0);
  const [obstacles, setObstacles] = useState<Obstacle[]>([]);
  const [gameOver, setGameOver] = useState(false);

  const gameRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(0);

  const jump = useCallback(() => {
    if (!isPlaying && !gameOver) {
      setIsPlaying(true);
      return;
    }
    if (gameOver) {
      resetGame();
      return;
    }
    setVelocity(JUMP_STRENGTH);
  }, [isPlaying, gameOver]);

  const resetGame = () => {
    setBirdY(CANVAS_HEIGHT / 2);
    setVelocity(0);
    setObstacles([]);
    setScore(0);
    setGameOver(false);
    setIsPlaying(true);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        jump();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [jump]);

  const update = (time: number) => {
    if (!lastTimeRef.current) lastTimeRef.current = time;
    const delta = time - lastTimeRef.current;

    if (isPlaying && !gameOver) {
      // Update bird
      setBirdY((prevY) => {
        const nextY = prevY + velocity;
        if (nextY < 0 || nextY > CANVAS_HEIGHT - BIRD_SIZE) {
          setGameOver(true);
          return prevY;
        }
        return nextY;
      });
      setVelocity((v) => v + GRAVITY);

      // Update obstacles
      setObstacles((prev) => {
        let next = prev.map((obs) => ({ ...obs, x: obs.x - OBSTACLE_SPEED }));

        // Remove off-screen
        next = next.filter((obs) => obs.x > -PIPE_WIDTH);

        // Spawn new
        if (next.length === 0 || next[next.length - 1].x < CANVAS_WIDTH - 200) {
          next.push({
            x: CANVAS_WIDTH,
            gapTop: Math.random() * (CANVAS_HEIGHT - PIPE_GAP - 100) + 50,
            passed: false,
          });
        }

        // Collision & Scoring
        next.forEach((obs) => {
          // Bird bounds
          const birdLeft = 50;
          const birdRight = 50 + BIRD_SIZE;
          const birdTop = birdY;
          const birdBottom = birdY + BIRD_SIZE;

          // Pipe bounds
          const pipeLeft = obs.x;
          const pipeRight = obs.x + PIPE_WIDTH;

          if (
            birdRight > pipeLeft &&
            birdLeft < pipeRight &&
            (birdTop < obs.gapTop || birdBottom > obs.gapTop + PIPE_GAP)
          ) {
            setGameOver(true);
          }

          if (!obs.passed && pipeRight < birdLeft) {
            obs.passed = true;
            setScore((s) => s + 1);
          }
        });

        return next;
      });
    }

    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(update);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, gameOver, velocity, birdY]);

  useEffect(() => {
    if (score > highScore) setHighScore(score);
  }, [score]);

  return (
    <div className="fixed bottom-6 left-6 z-[2000] flex flex-col items-start">
      {/* Game Window */}
      {isOpen && (
        <div className="mb-4 w-[300px] h-[450px] glass-effect rounded-[2.5rem] border border-white shadow-2xl overflow-hidden relative animate-[fadeIn_0.3s_ease-out]">
          <div className="absolute inset-0 bg-gradient-to-b from-sky-100/50 to-white/50 -z-10"></div>

          {/* Header */}
          <div className="flex items-center justify-between p-6 bg-white/40 backdrop-blur-sm border-b border-white/50">
            <div className="flex items-center space-x-2">
              <span className="text-lg">🎮</span>
              <span className="font-black text-sky-600 text-xs uppercase tracking-widest">Sky Dash</span>
            </div>
            <button 
              onClick={() => setIsOpen(false)}
              className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/50 transition-colors text-slate-400"
            >
              ✕
            </button>
          </div>

          {/* Game Canvas Simulation */}
          <div 
            className="relative w-full h-[calc(450px-72px)] cursor-pointer overflow-hidden"
            onClick={jump}
          >
            {/* Score */}
            <div className="absolute top-4 left-0 right-0 text-center z-20 pointer-events-none">
              <span className="text-4xl font-black text-sky-600 drop-shadow-sm">{score}</span>
            </div>

            {/* Clouds (Obstacles) */}
            {obstacles.map((obs, i) => (
              <React.Fragment key={i}>
                {/* Top Pipe */}
                <div 
                  className="absolute bg-white/60 border border-sky-100 rounded-b-2xl shadow-sm"
                  style={{ left: obs.x, top: 0, width: PIPE_WIDTH, height: obs.gapTop }}
                >
                  <div className="absolute bottom-0 left-0 w-full h-4 bg-sky-200/30"></div>
                </div>
                {/* Bottom Pipe */}
                <div 
                  className="absolute bg-white/60 border border-sky-100 rounded-t-2xl shadow-sm"
                  style={{ left: obs.x, top: obs.gapTop + PIPE_GAP, width: PIPE_WIDTH, height: CANVAS_HEIGHT - (obs.gapTop + PIPE_GAP) }}
                >
                  <div className="absolute top-0 left-0 w-full h-4 bg-sky-200/30"></div>
                </div>
              </React.Fragment>
            ))}

            {/* Bird (Plane) */}
            <div 
              className="absolute transition-transform duration-100"
              style={{ 
                left: 50, 
                top: birdY, 
                transform: `rotate(${velocity * 3}deg)`
              }}
            >
              <PlaneIcon className="w-8 h-8 text-sky-500 drop-shadow-md" />
            </div>

            {/* Background Details */}
            <div className="absolute bottom-0 w-full h-10 bg-sky-50/50 border-t border-sky-100"></div>

            {/* Overlays */}
            {!isPlaying && !gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-sky-50/20 backdrop-blur-[2px] z-30">
                <div className="w-16 h-16 bg-white rounded-3xl shadow-xl flex items-center justify-center mb-4 animate-bounce">
                  <PlaneIcon className="w-8 h-8 text-sky-500 rotate-12" />
                </div>
                <h3 className="text-xl font-black text-slate-800 mb-2">Siap Lepas Landas?</h3>
                <p className="text-[10px] font-black text-sky-600 uppercase tracking-widest bg-white px-4 py-2 rounded-full shadow-sm">Ketuk untuk Mulai</p>
              </div>
            )}

            {gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 backdrop-blur-md z-40 p-10 animate-[fadeIn_0.3s_ease-out]">
                <h2 className="text-3xl font-black text-slate-900 mb-2">Game Over</h2>
                <div className="w-full h-px bg-sky-100 mb-6"></div>
                <div className="flex justify-between w-full mb-8">
                  <div className="text-center">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Score</p>
                    <p className="text-3xl font-black text-sky-600">{score}</p>
                  </div>
                  <div className="text-center">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Best</p>
                    <p className="text-3xl font-black text-slate-800">{highScore}</p>
                  </div>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); resetGame(); }}
                  className="w-full py-4 bg-sky-500 text-white font-black rounded-2xl shadow-lg shadow-sky-100 hover:bg-sky-600 active:scale-95 transition-all text-sm uppercase tracking-widest"
                >
                  Main Lagi
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Floating Button */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-[1.8rem] flex items-center justify-center transition-all duration-500 shadow-2xl ${
          isOpen 
            ? 'bg-slate-800 text-white rotate-90' 
            : 'bg-white text-sky-500 hover:scale-110 active:scale-90 border border-blue-50'
        }`}
      >
        <span className="text-3xl">{isOpen ? '✕' : '🎮'}</span>
        {!isOpen && (
          <span className="absolute -top-1 -right-1 flex h-4 w-4">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-4 w-4 bg-sky-500"></span>
          </span>
        )}
      </button>
    </div>
  );
};

