const JUMP_STRENGTH = -7.5;
const OBSTACLE_SPEED = 3.2;
const BIRD_SIZE = 34;
const CANVAS_WIDTH = 300;
const CANVAS_HEIGHT = 450;
const PIPE_WIDTH = 60; // Wider for building feel
const PIPE_GAP = 150; // Slightly tighter for challenge

interface Obstacle {
  x: number;
  gapTop: number;
  passed: boolean;
  type: 'office' | 'residential' | 'tower';
}

const FlightGame: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [birdY, setBirdY] = useState(CANVAS_HEIGHT / 2);
  const [velocity, setVelocity] = useState(0);
  const [obstacles, setObstacles] = useState<Obstacle[]>([]);
  const [gameOver, setGameOver] = useState(false);

  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(0);

  const jump = useCallback(() => {
    if (!isPlaying && !gameOver) {
      setIsPlaying(true);
      return;
    }
    if (gameOver) {
      resetGame();
      return;
    }
    setVelocity(JUMP_STRENGTH);
  }, [isPlaying, gameOver]);

  const resetGame = () => {
    setBirdY(CANVAS_HEIGHT / 2);
    setVelocity(0);
    setObstacles([]);
    setScore(0);
    setGameOver(false);
    setIsPlaying(true);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        jump();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [jump]);

  const update = (time: number) => {
    if (!lastTimeRef.current) lastTimeRef.current = time;

    if (isPlaying && !gameOver) {
      // Update bird
      setBirdY((prevY) => {
        const nextY = prevY + velocity;
        if (nextY < 0 || nextY > CANVAS_HEIGHT - BIRD_SIZE) {
          setGameOver(true);
          return prevY;
        }
        return nextY;
      });
      setVelocity((v) => v + GRAVITY);

      // Update obstacles
      setObstacles((prev) => {
        let next = prev.map((obs) => ({ ...obs, x: obs.x - OBSTACLE_SPEED }));

        // Remove off-screen
        next = next.filter((obs) => obs.x > -PIPE_WIDTH);

        // Spawn new
        if (next.length === 0 || next[next.length - 1].x < CANVAS_WIDTH - 200) {
          const types: ('office' | 'residential' | 'tower')[] = ['office', 'residential', 'tower'];
          next.push({
            x: CANVAS_WIDTH,
            gapTop: Math.random() * (CANVAS_HEIGHT - PIPE_GAP - 120) + 60,
            passed: false,
            type: types[Math.floor(Math.random() * types.length)]
          });
        }

        // Collision & Scoring
        next.forEach((obs) => {
          const birdLeft = 50;
          const birdRight = 50 + BIRD_SIZE;
          const birdTop = birdY + 5; // hitbox adjustment
          const birdBottom = birdY + BIRD_SIZE - 5;

          const pipeLeft = obs.x;
          const pipeRight = obs.x + PIPE_WIDTH;

          if (
            birdRight > pipeLeft &&
            birdLeft < pipeRight &&
            (birdTop < obs.gapTop || birdBottom > obs.gapTop + PIPE_GAP)
          ) {
            setGameOver(true);
          }

          if (!obs.passed && pipeRight < birdLeft) {
            obs.passed = true;
            setScore((s) => s + 1);
          }
        });

        return next;
      });
    }

    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(update);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, gameOver, velocity, birdY]);

