            {gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 backdrop-blur-xl z-40 p-10 animate-[fadeIn_0.3s_ease-out]">
                <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-4xl mb-6 shadow-inner">💥</div>
