import React, { useState, useEffect, useRef, useCallback } from 'react';
import { PlaneIcon } from '../constants';

const GRAVITY = 0.45; 
const JUMP_STRENGTH = -7.2;
const OBSTACLE_SPEED = 3.3;
const BIRD_SIZE = 34;
const CANVAS_WIDTH = 300;
const CANVAS_HEIGHT = 450;
const PIPE_WIDTH = 65; 
const PIPE_GAP = 155; 

interface Obstacle {
  x: number;
  gapTop: number;
  passed: boolean;
  type: 'office' | 'residential' | 'tower';
}

const FlightGame: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [birdY, setBirdY] = useState(CANVAS_HEIGHT / 2);
  const [velocity, setVelocity] = useState(0);
  const [obstacles, setObstacles] = useState<Obstacle[]>([]);
  const [gameOver, setGameOver] = useState(false);

  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(0);

  const jump = useCallback(() => {
    if (!isPlaying && !gameOver) {
      setIsPlaying(true);
      return;
    }
    if (gameOver) {
      resetGame();
      return;
    }
    setVelocity(JUMP_STRENGTH);
  }, [isPlaying, gameOver]);

  const resetGame = () => {
    setBirdY(CANVAS_HEIGHT / 2);
    setVelocity(0);
    setObstacles([]);
    setScore(0);
    setGameOver(false);
    setIsPlaying(true);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        jump();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [jump]);

  const update = (time: number) => {
    if (!lastTimeRef.current) lastTimeRef.current = time;

    if (isPlaying && !gameOver) {
      setBirdY((prevY) => {
        const nextY = prevY + velocity;
        if (nextY < 0 || nextY > CANVAS_HEIGHT - BIRD_SIZE) {
          setGameOver(true);
          return prevY;
        }
        return nextY;
      });
      setVelocity((v) => v + GRAVITY);

      setObstacles((prev) => {
        let next = prev.map((obs) => ({ ...obs, x: obs.x - OBSTACLE_SPEED }));
        next = next.filter((obs) => obs.x > -PIPE_WIDTH);

        if (next.length === 0 || next[next.length - 1].x < CANVAS_WIDTH - 180) {
          const types: ('office' | 'residential' | 'tower')[] = ['office', 'residential', 'tower'];
          next.push({
            x: CANVAS_WIDTH,
            gapTop: Math.random() * (CANVAS_HEIGHT - PIPE_GAP - 130) + 65,
            passed: false,
            type: types[Math.floor(Math.random() * types.length)]
          });
        }

        next.forEach((obs) => {
          const birdLeft = 50;
          const birdRight = 50 + BIRD_SIZE;
          const birdTop = birdY + 8; 
          const birdBottom = birdY + BIRD_SIZE - 8;

          const pipeLeft = obs.x;
          const pipeRight = obs.x + PIPE_WIDTH;

          if (
            birdRight > pipeLeft &&
            birdLeft < pipeRight &&
            (birdTop < obs.gapTop || birdBottom > obs.gapTop + PIPE_GAP)
          ) {
            setGameOver(true);
          }

          if (!obs.passed && pipeRight < birdLeft) {
            obs.passed = true;
            setScore((s) => s + 1);
          }
        });

        return next;
      });
    }

    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(update);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, gameOver, velocity, birdY]);

  useEffect(() => {
    if (score > highScore) setHighScore(score);
  }, [score]);

  return (
    <div className="fixed bottom-6 left-6 z-[2000] flex flex-col items-start">
      {isOpen && (
        <div className="mb-4 w-[300px] h-[450px] glass-effect rounded-[2.5rem] border border-white shadow-2xl overflow-hidden relative animate-[fadeIn_0.3s_ease-out]">
          <div className="absolute inset-0 bg-gradient-to-b from-sky-300 via-sky-100 to-white -z-10"></div>

          <div className="flex items-center justify-between p-6 bg-white/70 backdrop-blur-md border-b border-white/50 relative z-50">
            <div className="flex items-center space-x-2">
              <span className="text-lg">🏙️</span>
              <span className="font-black text-sky-600 text-[10px] uppercase tracking-widest">Urban Flight</span>
            </div>
            <button 
              onClick={() => setIsOpen(false)}
              className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/90 transition-colors text-slate-400"
            >
              ✕
            </button>
          </div>

          <div 
            className="relative w-full h-[calc(450px-72px)] cursor-pointer overflow-hidden"
            onClick={jump}
          >
            <div className="absolute bottom-0 w-full flex items-end justify-between opacity-15 pointer-events-none px-4">
              <div className="w-10 h-24 bg-sky-600 rounded-t-xl"></div>
              <div className="w-14 h-40 bg-sky-800 rounded-t-xl"></div>
              <div className="w-8 h-28 bg-sky-500 rounded-t-xl"></div>
            </div>

            <div className="absolute top-4 left-0 right-0 text-center z-20 pointer-events-none">
              <span className="text-5xl font-black text-sky-600/90 drop-shadow-sm">{score}</span>
            </div>

            {obstacles.map((obs, i) => (
              <React.Fragment key={i}>
                <div 
                  className="absolute bg-slate-100 border-x-2 border-b-2 border-slate-300 shadow-xl flex flex-col overflow-hidden"
                  style={{ left: obs.x, top: 0, width: PIPE_WIDTH, height: obs.gapTop }}
                >
                  <div className="grid grid-cols-2 gap-2 p-2 w-full opacity-40">
                    {Array.from({ length: 15 }).map((_, idx) => (
                      <div key={idx} className="w-full h-3 bg-sky-300 rounded-sm"></div>
                    ))}
                  </div>
                  <div className="mt-auto w-full h-4 bg-slate-400"></div>
                </div>

                <div 
                  className="absolute bg-slate-100 border-x-2 border-t-2 border-slate-300 shadow-xl flex flex-col overflow-hidden"
                  style={{ left: obs.x, top: obs.gapTop + PIPE_GAP, width: PIPE_WIDTH, height: CANVAS_HEIGHT - (obs.gapTop + PIPE_GAP) }}
                >
                  <div className="w-full h-4 bg-slate-400"></div>
                  <div className="grid grid-cols-2 gap-2 p-2 w-full opacity-40">
                    {Array.from({ length: 15 }).map((_, idx) => (
                      <div key={idx} className="w-full h-3 bg-sky-300 rounded-sm"></div>
                    ))}
                  </div>
                </div>
              </React.Fragment>
            ))}

            <div 
              className="absolute transition-transform duration-75"
              style={{ 
                left: 50, 
                top: birdY, 
                transform: `rotate(${velocity * 2.5}deg)`
              }}
            >
              <div className="relative">
                <PlaneIcon className="w-10 h-10 text-sky-500 drop-shadow-[0_4px_10px_rgba(14,165,233,0.5)]" />
                <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-6 h-2 bg-gradient-to-r from-transparent to-sky-400/40 rounded-full blur-sm animate-pulse"></div>
              </div>
            </div>

            {!isPlaying && !gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-sky-50/20 backdrop-blur-[1px] z-30">
                <div className="w-16 h-16 bg-white rounded-[1.8rem] shadow-2xl flex items-center justify-center mb-6 animate-bounce border border-sky-50">
                  <PlaneIcon className="w-9 h-9 text-sky-500" />
                </div>
                <h3 className="text-xl font-black text-slate-800 mb-1">Urban Dash</h3>
                <p className="text-[10px] font-black text-sky-600 uppercase tracking-widest bg-white/80 px-5 py-2.5 rounded-full shadow-lg border border-sky-100">Tap to Takeoff</p>
              </div>
            )}

            {gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 backdrop-blur-xl z-40 p-10 animate-[fadeIn_0.3s_ease-out]">
                <div className="w-20 h-20 bg-red-50 text-red-500 rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-inner border border-red-100">💥</div>
                <h2 className="text-3xl font-black text-slate-900 mb-1 tracking-tighter">Emergency!</h2>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Penerbangan Dibatalkan</p>

                <div className="flex justify-between w-full mb-10 bg-sky-50/50 p-6 rounded-[2rem] border border-sky-100/50">
                  <div className="text-center">
                    <p className="text-[8px] font-black text-sky-400 uppercase tracking-widest mb-1">Current</p>
                    <p className="text-3xl font-black text-sky-600">{score}</p>
                  </div>
                  <div className="w-px bg-sky-100 mx-4"></div>
                  <div className="text-center">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Personal Best</p>
                    <p className="text-3xl font-black text-slate-800">{highScore}</p>
                  </div>
                </div>

                <button 
                  onClick={(e) => { e.stopPropagation(); resetGame(); }}
                  className="w-full py-4 bg-sky-500 text-white font-black rounded-2xl shadow-xl shadow-sky-200 hover:bg-sky-600 active:scale-95 transition-all text-sm uppercase tracking-widest"
                >
                  Restart Flight
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-[1.8rem] flex items-center justify-center transition-all duration-500 shadow-2xl ${
          isOpen 
            ? 'bg-slate-800 text-white rotate-90 scale-90' 
            : 'bg-white text-sky-500 hover:scale-110 active:scale-90 border border-blue-50'
        }`}
      >
        <span className="text-3xl">{isOpen ? '✕' : '🎮'}</span>
        {!isOpen && (
          <span className="absolute -top-1 -right-1 flex h-4 w-4">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-4 w-4 bg-sky-500"></span>
          </span>
        )}
      </button>
    </div>
  );
};

