                  <div className="grid grid-cols-2 gap-2 p-2 w-full opacity-40">
                    {Array.from({ length: 15 }).map((_, idx) => (
                      <div key={idx} className="w-full h-3 bg-sky-300 rounded-sm"></div>
                    ))}
                  </div>
                  <div className="mt-auto w-full h-4 bg-slate-400"></div>
                </div>

                <div 
                  className="absolute bg-slate-100 border-x-2 border-t-2 border-slate-300 shadow-xl flex flex-col overflow-hidden"
                  style={{ left: obs.x, top: obs.gapTop + PIPE_GAP, width: PIPE_WIDTH, height: CANVAS_HEIGHT - (obs.gapTop + PIPE_GAP) }}
                >
                  <div className="w-full h-4 bg-slate-400"></div>
                  <div className="grid grid-cols-2 gap-2 p-2 w-full opacity-40">
                    {Array.from({ length: 15 }).map((_, idx) => (
                      <div key={idx} className="w-full h-3 bg-sky-300 rounded-sm"></div>
                    ))}
                  </div>
                </div>
              </React.Fragment>
            ))}

            <div 
              className="absolute transition-transform duration-75"
              style={{ 
                left: 50, 
                top: birdY, 
                transform: `rotate(${velocity * 2.5}deg)`
              }}
            >
              <div className="relative">
                <PlaneIcon className="w-12 h-12 text-sky-500 drop-shadow-[0_4px_10px_rgba(14,165,233,0.5)]" />
                <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-6 h-2 bg-gradient-to-r from-transparent to-sky-400/40 rounded-full blur-sm animate-pulse"></div>
              </div>
            </div>

            {!isPlaying && !gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-sky-50/20 backdrop-blur-[1px] z-30">
                <div className="w-16 h-16 bg-white rounded-[1.8rem] shadow-2xl flex items-center justify-center mb-6 animate-bounce border border-sky-50">
                  <PlaneIcon className="w-9 h-9 text-sky-500" />
                </div>
                <h3 className="text-xl font-black text-slate-800 mb-1">Urban Dash</h3>
                <p className="text-[10px] font-black text-sky-600 uppercase tracking-widest bg-white/80 px-5 py-2.5 rounded-full shadow-lg border border-sky-100">Tap to Takeoff</p>
              </div>
            )}

            {gameOver && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 backdrop-blur-xl z-40 p-10 animate-[fadeIn_0.3s_ease-out]">
                <div className="w-20 h-20 bg-red-50 text-red-500 rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-inner border border-red-100">💥</div>
                <h2 className="text-3xl font-black text-slate-900 mb-1 tracking-tighter">Emergency!</h2>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Penerbangan Dibatalkan</p>

                <div className="flex justify-between w-full mb-10 bg-sky-50/50 p-6 rounded-[2rem] border border-sky-100/50">
                  <div className="text-center">
                    <p className="text-[8px] font-black text-sky-400 uppercase tracking-widest mb-1">Current</p>
                    <p className="text-3xl font-black text-sky-600">{score}</p>
                  </div>
                  <div className="w-px bg-sky-100 mx-4"></div>
                  <div className="text-center">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Personal Best</p>
                    <p className="text-3xl font-black text-slate-800">{highScore}</p>
                  </div>
                </div>

                <button 
                  onClick={(e) => { e.stopPropagation(); resetGame(); }}
                  className="w-full py-4 bg-sky-500 text-white font-black rounded-2xl shadow-xl shadow-sky-200 hover:bg-sky-600 active:scale-95 transition-all text-sm uppercase tracking-widest"
                >
                  Restart Flight
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-[1.8rem] flex items-center justify-center transition-all duration-500 shadow-2xl ${
          isOpen 
            ? 'bg-slate-800 text-white rotate-90 scale-90' 
            : 'bg-white text-sky-500 hover:scale-110 active:scale-90 border border-blue-50'
        }`}
      >
        <span className="text-3xl">{isOpen ? '✕' : '🎮'}</span>
        {!isOpen && (
          <span className="absolute -top-1 -right-1 flex h-4 w-4">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-sky-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-4 w-4 bg-sky-500"></span>
          </span>
        )}
      </button>
    </div>
  );
};

