      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error("CS Error:", error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSendMessage = (e?: React.FormEvent) => {
    e?.preventDefault();
    processMessage(inputValue);
