  const getStatusStyles = (status?: string) => {
    switch (status?.toLowerCase()) {
      case 'delayed':
        return 'bg-amber-50 text-amber-600 border-amber-100';
      case 'cancelled':
        return 'bg-red-50 text-red-600 border-red-100';
