const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [selectedFlight, setSelectedFlight] = useState<Flight | null>(null);
  const [isBookingOpen, setIsBookingOpen] = useState(false);

  const [searchParams, setSearchParams] = useState<SearchParams>({
    origin: 'Jakarta (CGK)',
    destination: '',
    date: new Date().toISOString().split('T')[0],
    passengers: 1,
    class: 'Economy'
  });
  const [flights, setFlights] = useState<Flight[]>([]);
  const [hasSearched, setHasSearched] = useState(false);
  const [aiMessage, setAiMessage] = useState<string>('');
  const [isTypingAI, setIsTypingAI] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchParams.destination) return;

    setIsLoading(true);
    setHasSearched(true);

    const results = await searchFlightsAI(searchParams.origin, searchParams.destination);

    const mockResults: Flight[] = results.length > 0 ? results.map((r: any) => ({
      ...r,
      from: searchParams.origin.split(' ')[0],
      to: searchParams.destination.split(' ')[0],
