      {
        id: '1',
        airline: 'SkyHigh Airways',
        logo: '✈️',
        departureTime: '08:00',
        arrivalTime: '11:30',
        duration: '3h 30m',
        from: searchParams.origin.split(' ')[0],
        to: searchParams.destination.split(' ')[0],
        price: 120,
        stops: 0,
