  const [password, setPassword] = useState('');

  const t = TRANSLATIONS[language].login;

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const actionMsg = isLogin 
      ? (language === 'id' ? "Mencoba masuk..." : "Trying to login...") 
